int binarySearch(int arr[], int n, int target) {
    int low = 0, high = n - 1, mid;

    while (low <= high) {
        // Calculate mid to avoid overflow
        mid = low + (high - low) / 2;

        if (arr[mid] == target) {
            return mid;  // Element found at index mid
        }
        else if (arr[mid] < target) {
            low = mid + 1;  // Search right half
        }
        else {
            high = mid - 1;  // Search left half
        }
    }

    return -1;  // Element not found
}

int binarySearchRecursive(int arr[], int low, int high, int target) {
    // Base case: search space exhausted
    if (low > high) {
        return -1;  // Element not found
    }

    // Calculate mid to avoid overflow
    int mid = low + (high - low) / 2;

    // Element found at mid
    if (arr[mid] == target) {
        return mid;
    }

    // Target is in the left half
    if (arr[mid] > target) {
        return binarySearchRecursive(arr, low, mid - 1, target);
    }

    // Target is in the right half
    return binarySearchRecursive(arr, mid + 1, high, target);
}

// Wrapper function
int binarySearch(int arr[], int n, int target) {
    return binarySearchRecursive(arr, 0, n - 1, target);
}

#include <stdio.h>

int binarySearch(int arr[], int n, int target) {
    int low = 0, high = n - 1, mid;

    while (low <= high) {
        mid = low + (high - low) / 2;

        if (arr[mid] == target) {
            return mid;
        }
        else if (arr[mid] < target) {
            low = mid + 1;
        }
        else {
            high = mid - 1;
        }
    }
    return -1;
}

int main() {
    int arr[] = {2, 5, 8, 12, 16, 23, 38, 56, 72, 91};
    int n = sizeof(arr) / sizeof(arr[0]);
    int testCases[] = {23, 2, 91, 100, 16};
    int results[] = {5, 0, 9, -1, 4};

    printf("Binary Search Demonstration\n");
    printf("Array: ");
    for (int i = 0; i < n; i++) printf("%d ", arr[i]);
    printf("\n\n");

    for (int i = 0; i < 5; i++) {
        int target = testCases[i];
        int result = binarySearch(arr, n, target);
        printf("Search for %d: ", target);
        if (result != -1)
            printf("Found at index %d (Expected: %d)\n", result, results[i]);
        else
            printf("Not found (Expected: %d)\n", results[i]);
    }
    return 0;
}
